import java.util.ArrayList;

class Solution {
    public List<Integer> constructArray(int n, int k) {
        ArrayList<Integer> answer = new ArrayList<>(n);
        for (int i = 0; i < n; i++) {
            if (i % 2 == 0) {
                answer.add(i / 2 + 1);
            } else {
                answer.add(n - (i - 1) / 2);
                k--;
            }
        }
        if (k > 0) {
            for (int i = n - 2; i >= 0 && k > 0; i--) {
                answer.set(i, answer.get(i + 1) - answer.get(i));
                k--;
            }
        }
        return answer;
    }
}
```

